// Get tracker data and drive files
const trackerRows = $('📊 Read Video Tracker (Google Sheets)').all();
const driveFiles = $('📁 List Google Drive Videos').all();

// Build list of posted video IDs from tracker
const postedVideoIds = new Set(
  trackerRows
    .map(row => row.json['Video ID'])
    .filter(id => id && id.trim() !== '')
);

// Filter to only video files, sorted alphabetically/by name
const allVideos = driveFiles
  .map(f => ({
    id: f.json.id,
    name: f.json.name,
    mimeType: f.json.mimeType,
    size: f.json.size,
    createdTime: f.json.createdTime
  }))
  .filter(f => f.mimeType && f.mimeType.startsWith('video/'))
  .sort((a, b) => a.name.localeCompare(b.name));

// Find next unposted video
const nextVideo = allVideos.find(v => !postedVideoIds.has(v.id));

if (!nextVideo) {
  // All videos posted — start over or alert
  return [{
    json: {
      status: 'ALL_VIDEOS_POSTED',
      message: 'All videos in the folder have been posted. Please add more videos.',
      totalVideos: allVideos.length,
      postedCount: postedVideoIds.size,
      timestamp: new Date().toISOString()
    }
  }];
}

const today = new Date();
const dateIST = today.toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', year: 'numeric', month: '2-digit', day: '2-digit' });

return [{
  json: {
    status: 'VIDEO_FOUND',
    videoId: nextVideo.id,
    videoName: nextVideo.name,
    videoTitle: nextVideo.name.replace(/\.[^/.]+$/, '').replace(/[-_]/g, ' '),
    mimeType: nextVideo.mimeType,
    fileSize: nextVideo.size,
    dateIST: dateIST,
    totalVideos: allVideos.length,
    postedCount: postedVideoIds.size,
    remainingCount: allVideos.length - postedVideoIds.size - 1,
    queuePosition: allVideos.findIndex(v => v.id === nextVideo.id) + 1,
    timestamp: new Date().toISOString()
  }
}];

// Generate engaging captions with strategic hashtags
const videoData = $('🧠 Determine Next Video').item.json;
const rawTitle = videoData.videoTitle || 'Amazing Video';

// Capitalize words
const formatTitle = (str) => str
  .split(' ')
  .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
  .join(' ');

const cleanTitle = formatTitle(rawTitle);

// Caption templates for variety and engagement
const captionTemplates = [
  `✨ ${cleanTitle}\n\nEvery day is a new opportunity to create something amazing! Today's content is here to inspire, educate, and entertain you. 🎯\n\nDrop a 🔥 if you loved this! Share with someone who needs to see this today.\n\n👇 Comment below — what do you want to see next?`,

  `🎬 ${cleanTitle}\n\nWe show up EVERY. SINGLE. DAY. Because consistency is the real secret to success. 💪\n\nTag a friend who needs this content! 👥\n\n📌 Save this post for later — you'll thank yourself! \n\nDouble tap if this resonated with you! ❤️`,

  `🚀 ${cleanTitle}\n\nMost people scroll past content like this. The ones who STOP and ENGAGE are the ones who grow. 🌱\n\nWhich part hit different for you? Tell us in the comments! 👇\n\n💾 Save + Share = More amazing content coming your way!`,

  `💡 ${cleanTitle}\n\nYou found this for a reason. The algorithm brought you here — don't ignore the sign! 🙏\n\nHit LIKE if you agree + FOLLOW for daily uploads! \n\n🎯 Our mission: deliver value every single day. Did we succeed today? Comment YES or NO!`,

  `⚡ ${cleanTitle}\n\nStop scrolling — THIS is the content you've been looking for. 🎯\n\nOur community gets FIRST ACCESS to everything. Hit that FOLLOW button NOW! 🔔\n\n📢 Share this with 3 friends and spread the value!`
];

// Pick a template based on day of week for variety
const dayOfWeek = new Date().getDay();
const selectedTemplate = captionTemplates[dayOfWeek % captionTemplates.length];

// Strategic hashtag sets for maximum reach
const coreHashtags = `#viral #trending #fyp #foryou #foryoupage #explore #reels #reelsinstagram #video`;

const engagementHashtags = `#follow #like #share #comment #save #explorepage #instagram #youtube #content`;

const growthHashtags = `#grow #growyouraccount #socialmedia #socialmediamarketing #contentcreator #creator #digitalmarketing #onlinebusiness #motivation`;

const niche1 = `#dailycontent #dailypost #everyday #consistency #contentcreation #videocontent #shortsvideo`;

// Full caption for Instagram (2200 char limit)
const instagramCaption = `${selectedTemplate}\n\n━━━━━━━━━━━━━━━━━━\n${coreHashtags} ${engagementHashtags} ${growthHashtags} ${niche1}`;

// YouTube description (more SEO focused)
const youtubeDescription = `${selectedTemplate}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n📌 SUBSCRIBE for daily videos — New content EVERY DAY at 9 AM!\n🔔 Hit the Bell Icon to never miss an upload!\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n👇 LET'S CONNECT!\n📸 Instagram: https://instagram.com/{{YOUR_INSTAGRAM}}\n🎬 YouTube: https://youtube.com/{{YOUR_CHANNEL}}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🔑 KEYWORDS & TAGS\n${coreHashtags} ${engagementHashtags} ${growthHashtags}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n⚠️ COPYRIGHT DISCLAIMER\nAll content is original and owned by this channel.`;

// YouTube tags (for metadata)
const youtubeTags = [
  cleanTitle,
  'viral', 'trending', 'fyp', 'foryou', 'reels', 'shorts',
  'daily content', 'content creator', 'motivation', 'inspiration',
  'social media', 'youtube', 'instagram', 'video', 'consistency',
  'grow your account', 'digital marketing', 'online business'
];

const today = new Date();
const youtubeTitle = `${cleanTitle} | ${today.toLocaleDateString('en-IN', {timeZone:'Asia/Kolkata', day:'2-digit', month:'short', year:'numeric'})}`;

return [{
  json: {
    videoId: videoData.videoId,
    videoName: videoData.videoName,
    cleanTitle: cleanTitle,
    youtubeTitle: youtubeTitle,
    instagramCaption: instagramCaption,
    youtubeDescription: youtubeDescription,
    youtubeTags: youtubeTags,
    dateIST: videoData.dateIST,
    queuePosition: videoData.queuePosition,
    remainingCount: videoData.remainingCount,
    timestamp: videoData.timestamp
  }
}];

// Log the failed Instagram container status for reporting
const containerStatus = $json;
const captionData = $('✍️ Generate Caption & Hashtags').item.json;

return [{
  json: {
    failReason: 'Instagram container status: ' + (containerStatus.status_code || 'UNKNOWN'),
    videoName: captionData.cleanTitle,
    videoId: captionData.videoId,
    dateIST: captionData.dateIST,
    containerStatus: containerStatus
  }
}];

// Catch-all error handler for the workflow
const errorData = $json;
const now = new Date().toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'});

return [{
  json: {
    errorType: 'WORKFLOW_ERROR',
    error: errorData.message || 'Unknown error occurred',
    node: errorData.node?.name || 'Unknown node',
    timestamp: now,
    rawError: JSON.stringify(errorData).substring(0, 500)
  }
}];
